16	// FindProjectRoot walks up from startDir to find the git repository root.
17	// It returns the top-level directory of the git working tree. If startDir
18	// is not inside a git repository, it returns startDir unchanged.
19	//
20	// This is analogous to `git rev-parse --show-toplevel` and ensures that
21	// ddx always operates from the repository root regardless of the caller's
22	// working directory. Without this, running `ddx` from a subdirectory that
23	// contains its own `.ddx/` folder would silently use the wrong workspace.
24	func FindProjectRoot(startDir string) string {
25		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
26		defer cancel()
27	
28		cmd := exec.CommandContext(ctx, "git", "rev-parse", "--show-toplevel")
29		cmd.Dir = startDir
30		out, err := cmd.Output()
31		if err != nil {
32			// Not in a git repo — fall back to the original directory.
33			return startDir
34		}
35		root := strings.TrimSpace(string(out))
36		if root == "" {
37			return startDir
38		}
39		return root
