42	// FindNearestDDxWorkspace walks up from startDir to find the nearest ancestor
43	// inside the current git repository that contains a .ddx workspace.
44	//
45	// When startDir is inside a linked git worktree (e.g. an execute-bead
46	// isolated worktree under .ddx/.execute-bead-wt-* or a worktrunk sibling
47	// like repo.feature-branch/), it resolves to the PRIMARY worktree's .ddx/
48	// first, not the linked worktree's own .ddx/. This is critical because:
49	//
50	//   - bead store mutations must land in the canonical project bead queue,
51	//     not in an isolated worktree's private snapshot that will be discarded
52	//   - the primary worktree is the operator's source of truth; linked
53	//     worktrees are ephemeral execution contexts
54	//
55	// If the primary worktree has no .ddx/ (or we aren't in a linked worktree),
56	// it falls back to walking up from startDir within the current git
57	// repository.
58	//
59	// Returns an empty string if no .ddx/ is found.
60	func FindNearestDDxWorkspace(startDir string) string {
61		abs, err := filepath.Abs(startDir)
62		if err != nil {
63			return ""
64		}
65	
66		// If we're inside a linked worktree, prefer the primary worktree's .ddx/.
67		if primary := primaryWorktreeRoot(abs); primary != "" && primary != FindProjectRoot(abs) {
68			candidate := filepath.Join(primary, ".ddx")
69			if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
70				return primary
71			}
72		}
73	
74		gitRoot := FindProjectRoot(abs)
75		current := abs
