282	// isValidPath validates a file system path
283	func isValidPath(path string) bool {
284		if path == "" {
285			return false
286		}
287	
288		// Check cache first for performance
289		if cached, exists := pathValidationCache.Load(path); exists {
290			return cached.(bool)
291		}
292	
293		// Basic path validation
294		cleanPath := filepath.Clean(path)
295	
296		// Prevent path traversal
297		if strings.Contains(cleanPath, "..") {
298			pathValidationCache.Store(path, false)
299			return false
300		}
301	
302		// Prevent absolute paths outside current working directory for safety
303		if filepath.IsAbs(cleanPath) {
304			pwd, err := filepath.Abs(".")
305			if err != nil {
306				pathValidationCache.Store(path, false)
307				return false
308			}
309	
310			// Check if the path is within or equal to current directory
311			rel, err := filepath.Rel(pwd, cleanPath)
312			if err != nil || strings.HasPrefix(rel, "..") {
313				pathValidationCache.Store(path, false)
314				return false
315			}
316		}
317	
318		pathValidationCache.Store(path, true)
319		return true
320	}
