349	// validateRepoURL validates a git repository URL
350	func validateRepoURL(repoURL string) error {
351		if repoURL == "" {
352			return fmt.Errorf("repository URL cannot be empty")
353		}
354	
355		if len(repoURL) > 2048 {
356			return fmt.Errorf("repository URL too long (max 2048 characters)")
357		}
358	
359		// Parse URL to validate format
360		u, err := url.Parse(repoURL)
361		if err != nil {
362			return fmt.Errorf("invalid URL format: %w", err)
363		}
364	
365		// Only allow specific schemes for security
366		allowedSchemes := map[string]bool{
367			"http":  true,
368			"https": true,
369			"git":   true,
370			"ssh":   true,
371		}
372	
373		// Allow file:// URLs for testing (when running in test environments)
374		// This is detected by checking if we're in a temp directory used by tests
375		if u.Scheme == "file" && (strings.Contains(repoURL, "/tmp/") || strings.Contains(repoURL, os.TempDir())) {
376			allowedSchemes["file"] = true
377		}
378	
379		if !allowedSchemes[u.Scheme] {
380			return fmt.Errorf("unsupported URL scheme: %s (allowed: http, https, git, ssh)", u.Scheme)
381		}
382	
383		// Additional validation for git URLs
384		if u.Scheme == "git" || u.Scheme == "ssh" {
385			// Basic validation for git/ssh URLs
386			if u.Host == "" {
387				return fmt.Errorf("git/ssh URLs must have a host")
388			}
389		}
390	
391		return nil
392	}
