161			if !ok || sel.Sel == nil || sel.Sel.Name != "Prompt" {
162				continue
163			}
164			// Resolve the type of sel.X.
165			t := pass.TypesInfo.TypeOf(sel.X)
166			if t == nil {
167				continue
168			}
169			if !typeIsRunOptions(t) {
