181	func typeIsRunOptions(t types.Type) bool {
182		// Strip pointers.
183		for {
184			p, ok := t.(*types.Pointer)
185			if !ok {
186				break
187			}
188			t = p.Elem()
189		}
190		named, ok := t.(*types.Named)
191		if !ok {
192			return false
193		}
194		obj := named.Obj()
195		if obj == nil {
196			return false
197		}
198		if !runOptionsTypeNames[obj.Name()] {
199			// Not RunOptions itself; check if the underlying struct embeds RunOptions.
200			st, ok := named.Underlying().(*types.Struct)
201			if !ok {
202				return false
203			}
204			for i := 0; i < st.NumFields(); i++ {
205				f := st.Field(i)
206				if !f.Anonymous() {
207					continue
208				}
209				if typeIsRunOptions(f.Type()) {
210					return true
211				}
212			}
213			return false
214		}
215		if obj.Pkg() == nil {
216			return false
217		}
218		return pkgPathHasSuffix(obj.Pkg().Path(), runOptionsPkgSuffixes)
219	}
